<template>
    <div>
      <div class="row" v-for="(row, rowIndex) in config" :key="rowIndex">
        <component
          v-for="(cell, cellIndex) in row"
          :key="cellIndex"
          :is="cell.component"
          v-bind="cell.props"
        ></component>
      </div>
    </div>
  </template>
<script>
// import {ComponentConfig} from '../models/interfaces'
import { ref } from 'vue';

const dynamicComponents = ref({});

export default {
  name: "AnyRender",
  props: {
     // @ts-ignore
    config: {
      type: Array,
      default: () => []
    }
  },
  mounted() {
    this.config.forEach(row => {
      row.forEach(cell => {
        console.log(cell)
        dynamicComponents.value[cell.component.name] = cell.component;
      });
    });
  }
};
</script>
<style>
.row {
  display: flex;
  justify-content: space-around; 
}
</style>
